function addCityMarker(pos){
new google.maps.Circle({map,center:pos,radius:500,fillColor:'#52b788',fillOpacity:.12,strokeColor:'#52b788',strokeOpacity:.3,strokeWeight:1});
}
async function searchNearbyREST(lat, lng, radiusM){
const url='https://places.googleapis.com/v1/places:searchNearby';
const body={
includedTypes:['mosque'],
maxResultCount:20,
locationRestriction:{
circle:{
center:{latitude:lat, longitude:lng},
radius: Math.min(radiusM, 50000),
}
}
};
const res=await fetch(url,{
method:'POST',
headers:{
'Content-Type':'application/json',
'X-Goog-Api-Key': GOOGLE_API_KEY,
'X-Goog-FieldMask':'places.id,places.displayName,places.location,places.rating,places.userRatingCount,places.formattedAddress',
},
body: JSON.stringify(body),
});
if(!res.ok) throw new Error(await res.text());
const data=await res.json();
return (data.places||[]).map(p=>normPlace(p));
}
function normPlace(p){
let lat, lng, name, rating, reviews, address, id;
if(p.location&&p.location.latitude!==undefined){
lat=p.location.latitude; lng=p.location.longitude;
name=p.displayName&&p.displayName.text||p.displayName||'';
rating=p.rating||0;
reviews=p.userRatingCount||0;
address=p.formattedAddress||'';
id=p.id||p.name||'';
} else {
lat=p.location.lat(); lng=p.location.lng();
name=p.displayName||'';
rating=p.rating||0;
reviews=p.userRatingCount||0;
address=p.formattedAddress||'';
id=p.id||'';
}
return {
place_id: id,
name,
rating,
user_ratings_total: reviews,
vicinity: address,
geometry:{ location:{ _lat:lat, _lng:lng, lat:()=>lat, lng:()=>lng } },
_latLng: new google.maps.LatLng(lat,lng),
};
}
async function searchNearbyNew(center, radiusM){
return searchNearbyREST(center.lat, center.lng, radiusM);
}
async function searchNearbyForPoint(latLng, radiusM){
return searchNearbyREST(latLng.lat(), latLng.lng(), radiusM);
}
async function startNearby(){
const btn=document.getElementById('btnLocate');
btn.disabled=true; btn.innerHTML=spin(13)+' Konum aliniyor...';
try{
if(!mapLoaded)await initMap(ANKARA);
clearAllMarkers();
if(routePolyline){routePolyline.setMap(null);routePolyline=null;}
routeRawAll=[]; routeMosques=[];
document.getElementById('routeCount').textContent='0';
document.getElementById('routeList').innerHTML=`<div class="smsg"><div class="ico">🗺</div><h3>Guzergah Girin</h3><p>Baslangic ve varis noktasini girin ya da haritadan secin.</p></div>`;
const pos=await new Promise((res,rej)=>navigator.geolocation.getCurrentPosition(res,rej,{timeout:10000}));
userLocation={lat:pos.coords.latitude,lng:pos.coords.longitude};
map.panTo(userLocation); map.setZoom(13);
placeUserPin(userLocation);
const oi=document.getElementById('originInput');
if(!oi.value||oi.dataset.useGPS==='1'||oi.value==='Konumunuz'){
oi.value='Konumunuz'; oi.dataset.coord=`${userLocation.lat},${userLocation.lng}`; oi.dataset.useGPS='1';
}
await fetchNearby(userLocation, parseInt(document.getElementById('radiusSelect').value));
toast('Konum alindi!');
}catch(e){
toast('Hata: '+(e.code===1?'Konum izni reddedildi.':(e.message||'Konum alinamadi.')));
}finally{btn.disabled=false;btn.textContent='Konumumu Bul'}
}
async function fetchNearby(center, radius){
showLoading('nearbyList');
clearMarkerArr(nearbyMarkers);
const dist = nearbyFetched.center
? google.maps.geometry.spherical.computeDistanceBetween(
new google.maps.LatLng(center.lat,center.lng),
new google.maps.LatLng(nearbyFetched.center.lat,nearbyFetched.center.lng))
: Infinity;
if(dist < 50 && radius <= nearbyFetched.radius && nearbyRawAll.length){
finalizeNearby(nearbyRawAll, radius, center);
return;
}
const cached = loadNearbyCache();
if(cached){
const cachedDist = google.maps.geometry.spherical.computeDistanceBetween(
new google.maps.LatLng(center.lat,center.lng),
new google.maps.LatLng(cached.center.lat,cached.center.lng));
if(cachedDist < 50 && radius <= cached.radius){
nearbyRawAll = cached.places;
nearbyFetched = { radius: cached.radius, center: cached.center };
finalizeNearby(nearbyRawAll, radius, center);
toast('Onceki sonuclar yuklendi (cache).');
return;
}
}
try{
const results = await searchNearbyNew(center, radius);
nearbyRawAll = results;
nearbyFetched = { radius, center };
saveNearbyCache(center, radius, results);
finalizeNearby(results, radius, center);
}catch(e){
showEmpty('nearbyList','Arama hatasi: '+e.message);
}
}
function finalizeNearby(all, radius, center){
clearMarkerArr(nearbyMarkers);
const {minR,minRev}=getNQ();
const centerLL = center ? new google.maps.LatLng(center.lat,center.lng) : null;
nearbyMosques = all.filter(p=>{
if(!passQ(p,minR,minRev))return false;
if(centerLL && p._latLng){
const pLL = typeof p._latLng.lat==='function'
? p._latLng
: new google.maps.LatLng(p._latLng.lat,p._latLng.lng);
const d=google.maps.geometry.spherical.computeDistanceBetween(centerLL,pLL);
return d<=radius;
}
return true;
}).sort((a,b)=>popScore(b)-popScore(a)).slice(0,20);
document.getElementById('nearbyCount').textContent=nearbyMosques.length;
if(!nearbyMosques.length){
showEmpty('nearbyList',`${minR}+ yildiz ve ${fmt(minRev)}+ yorumlu cami bulunamadi.`);
return;
}
renderList('nearbyList',nearbyMosques,'nearby');
nearbyMosques.forEach((m,i)=>nearbyMarkers.push(makeMosqueMarker(m,i,'nearby')));
}
function onNearbyQChange(){
if(nearbyRawAll.length) finalizeNearby(nearbyRawAll, parseInt(document.getElementById('radiusSelect').value), nearbyFetched.center);
}
async function onRadiusChange(){
if(!mapLoaded||!userLocation)return;
const r=parseInt(document.getElementById('radiusSelect').value);
await fetchNearby(userLocation,r);
}
async function computeRoute(origin, destination, waypoints){
const intermediates=waypoints.map(ll=>({
location:{latLng:{latitude:ll.lat,longitude:ll.lng}},
}));
const body={
origin:{location:{latLng:{latitude:origin.lat,longitude:origin.lng}}},
destination:{location:{latLng:{latitude:destination.lat,longitude:destination.lng}}},
intermediates,
travelMode:'DRIVE',
routingPreference:'TRAFFIC_UNAWARE',
polylineQuality:'HIGH_QUALITY',
computeAlternativeRoutes:false,
};
const res=await fetch('https://routes.googleapis.com/directions/v2:computeRoutes',{
method:'POST',
headers:{
'Content-Type':'application/json',
'X-Goog-Api-Key':GOOGLE_API_KEY,
'X-Goog-FieldMask':'routes.polyline.encodedPolyline,routes.legs,routes.distanceMeters,routes.duration',
},
body:JSON.stringify(body),
});
if(!res.ok)throw new Error('Routes API hatasi: '+res.status+' '+await res.text());
const data=await res.json();
if(!data.routes||!data.routes[0])throw new Error('Guzergah bulunamadi.');
return data.routes[0];
}
function decodePolyline(encoded){
const pts=[]; let idx=0,lat=0,lng=0;
while(idx<encoded.length){
let b,shift=0,result=0;
do{b=encoded.charCodeAt(idx++)-63;result|=(b&0x1f)<<shift;shift+=5}while(b>=0x20);
lat+=(result&1)?~(result>>1):(result>>1);
shift=0;result=0;
do{b=encoded.charCodeAt(idx++)-63;result|=(b&0x1f)<<shift;shift+=5}while(b>=0x20);
lng+=(result&1)?~(result>>1):(result>>1);
pts.push(new google.maps.LatLng(lat/1e5,lng/1e5));
}
return pts;
}
function drawRoutePolyline(path){
if(routePolyline)routePolyline.setMap(null);
routePolyline=new google.maps.Polyline({
path, map,
strokeColor:'#c9a84c',
strokeWeight:5,
strokeOpacity:.85,
});
}
async function startRoute(){
const destInp=document.getElementById('destInput');
if(!(destInp.value||'').trim()){toast('Varis noktasi girin.');return}
const btn=document.getElementById('btnRoute');
btn.disabled=true; btn.innerHTML=spin(13)+' Hesaplaniyor...';
try{
if(!mapLoaded)await initMap(ANKARA);
clearMarkerArr(nearbyMarkers);
clearMarkerArr(routeMarkers);
clearMarkerArr(epMarkers);
if(routePolyline){routePolyline.setMap(null);routePolyline=null;}
const originInp=document.getElementById('originInput');
let originLL;
const hasPickedCoord = originInp.dataset.coord && !originInp.dataset.useGPS;
if(hasPickedCoord){
const[la,ln]=originInp.dataset.coord.split(',').map(Number);
originLL={lat:la,lng:ln};
} else if(!originInp.value.trim()||originInp.dataset.useGPS==='1'){
if(!userLocation){
const pos=await new Promise((res,rej)=>navigator.geolocation.getCurrentPosition(res,rej,{timeout:8000}));
userLocation={lat:pos.coords.latitude,lng:pos.coords.longitude};
placeUserPin(userLocation);
}
originLL=userLocation;
} else {
originLL=await resolveLocation(originInp);
}
const destLL=await resolveLocation(destInp);
const stopLLs=[];
for(const row of document.querySelectorAll('#stopsContainer .stop-row')){
const inp=row.querySelector('input');
if(!inp||!(inp.value||'').trim())continue;
try{stopLLs.push(await resolveLocation(inp))}catch{}
}
const route=await computeRoute(originLL,destLL,stopLLs);
const path=decodePolyline(route.polyline.encodedPolyline);
lastRoutePath=path;
drawRoutePolyline(path);
const bounds=new google.maps.LatLngBounds();
path.forEach(p=>bounds.extend(p));
map.fitBounds(bounds,{padding:80});
epMarkers.push(makeAdvMarker(originLL,'#2d6a4f',1.1,'Baslangic'));
epMarkers.push(makeAdvMarker(destLL,'#c0392b',1.1,'Varis'));
stopLLs.forEach((ll,i)=>epMarkers.push(makeAdvMarker(ll,'#e67e22',1.0,'Durak '+(i+1))));
await searchCorridor(path,originLL,destLL);
toast('Guzergah hazir!');
}catch(e){
toast('Hata: '+e.message);
}finally{
btn.disabled=false;btn.textContent='Guzergahi Goster';
}
}
async function searchCorridor(path, originLL, destLL){
showLoading('routeList');
clearMarkerArr(routeMarkers);
const corridor=parseInt(document.getElementById('corridorWidth').value);
const cacheKey=[
originLL.lat.toFixed(3), originLL.lng.toFixed(3),
destLL.lat.toFixed(3), destLL.lng.toFixed(3),
corridor,
].join('|');
const cached = getCorridorCached(cacheKey);
if(cached){
routeRawAll = cached;
applyRouteFilter();
toast('Guzergah camileri onceki aramadan yuklendi (cache).');
return;
}
const searchR=Math.max(corridor,5000);
const stepM=searchR*1.5;
const samplePoints=[];
let cumDist=0, nextDist=0;
samplePoints.push(path[0]);
for(let i=1;i<path.length;i++){
cumDist+=google.maps.geometry.spherical.computeDistanceBetween(path[i-1],path[i]);
if(cumDist>=nextDist+stepM){
samplePoints.push(path[i]);
nextDist=cumDist;
}
}
samplePoints.push(path[path.length-1]);
const seen=new Map();
await Promise.all(samplePoints.map(async wp=>{
try{
const results = await searchNearbyForPoint(wp, searchR);
results.forEach(r=>{
if(!seen.has(r.place_id)){seen.set(r.place_id,r);placeCache.set(r.place_id,r)}
});
}catch(e){}
}));
routeRawAll=Array.from(seen.values()).filter(m=>{
const loc=m.geometry&&m.geometry.location;
if(!loc)return false;
const lat=typeof loc.lat==='function'?loc._lat:loc.lat;
const lng=typeof loc.lng==='function'?loc._lng:loc.lng;
const ll=new google.maps.LatLng(lat,lng);
return path.some(pt=>google.maps.geometry.spherical.computeDistanceBetween(pt,ll)<=corridor);
});
saveCorridorCache(cacheKey, routeRawAll);
applyRouteFilter();
}
function applyRouteFilter(){
clearMarkerArr(routeMarkers);
const{minR,minRev}=getRQ();
routeMosques=routeRawAll
.filter(m=>passQ(m,minR,minRev))
.sort((a,b)=>popScore(b)-popScore(a))
.slice(0,40);
document.getElementById('routeCount').textContent=routeMosques.length;
if(!routeMosques.length){
showEmpty('routeList',`${minR}+ yildiz ve ${fmt(minRev)}+ yorumlu cami bulunamadi. Filtre veya koridor mesafesini degistirin.`);
return;
}
renderList('routeList',routeMosques,'route');
routeMosques.forEach((m,i)=>routeMarkers.push(makeMosqueMarker(m,i,'route')));
}
function onRouteQChange(){if(routeRawAll.length)applyRouteFilter()}
function clearAll(){
if(routePolyline){routePolyline.setMap(null);routePolyline=null}
clearAllMarkers();
nearbyMosques=[]; routeMosques=[];
nearbyRawAll=[]; routeRawAll=[];
nearbyFetched={radius:0,center:null};
lastRoutePath=null;
sessionStorage.removeItem(CACHE_KEY_NEARBY);
sessionStorage.removeItem(CACHE_KEY_CORRIDOR);
document.getElementById('nearbyCount').textContent='0';
document.getElementById('routeCount').textContent='0';
document.getElementById('nearbyList').innerHTML=`<div class="smsg"><div class="ico">🕌</div><h3>Temizlendi</h3><p>Yeni arama yapabilirsiniz.</p></div>`;
document.getElementById('routeList').innerHTML=`<div class="smsg"><div class="ico">🗺</div><h3>Temizlendi</h3><p>Yeni guzergah girebilirsiniz.</p></div>`;
document.getElementById('originInput').value=userLocation?'Konumunuz':'';
document.getElementById('originInput').dataset.coord=userLocation?`${userLocation.lat},${userLocation.lng}`:'';
document.getElementById('originInput').dataset.useGPS=userLocation?'1':'';
document.getElementById('destInput').value='';
document.getElementById('destInput').dataset.coord='';
document.getElementById('stopsContainer').innerHTML='';
stopCount=0;
cancelPicking();
}
function getSavedRoutes(){
try{return JSON.parse(localStorage.getItem('camiRoutes')||'[]')}catch{return[]}
}
function setSavedRoutes(arr){localStorage.setItem('camiRoutes',JSON.stringify(arr))}
function loadSavedRoutesUI(){
const sel=document.getElementById('savedRoutesSel');
const routes=getSavedRoutes();
sel.innerHTML='<option value="">-- Kayitli rota sec --</option>';
routes.forEach((r,i)=>sel.add(new Option(r.name,i)));
}
function saveRoute(){
const origin=document.getElementById('originInput').value.trim();
const dest=document.getElementById('destInput').value.trim();
if(!dest){toast('Varis noktasi olmadan rota kaydedilemez.');return}
const routes=getSavedRoutes();
if(routes.length>=MAX_SAVED){toast(`En fazla ${MAX_SAVED} rota kaydedilebilir. Once bir tanesini silin.`);return}
const stops=[];
document.querySelectorAll('#stopsContainer .stop-row input').forEach(inp=>{
if(inp.value.trim())stops.push({value:inp.value,coord:inp.dataset.coord||''});
});
const idx=routes.length+1;
routes.push({
name:`${idx}. Kaydedilen Rota`,
origin:{value:origin,coord:document.getElementById('originInput').dataset.coord||'',useGPS:document.getElementById('originInput').dataset.useGPS||''},
dest:{value:dest,coord:document.getElementById('destInput').dataset.coord||''},
stops,
corridor:document.getElementById('corridorWidth').value,
});
setSavedRoutes(routes);
loadSavedRoutesUI();
toast('Rota kaydedildi!');
}
function loadSavedRoute(){
const sel=document.getElementById('savedRoutesSel');
const idx=parseInt(sel.value);
if(isNaN(idx))return;
const routes=getSavedRoutes();
const r=routes[idx];if(!r)return;
const oi=document.getElementById('originInput');
oi.value=r.origin.value; oi.dataset.coord=r.origin.coord; oi.dataset.useGPS=r.origin.useGPS||'';
document.getElementById('destInput').value=r.dest.value;
document.getElementById('destInput').dataset.coord=r.dest.coord||'';
document.getElementById('stopsContainer').innerHTML=''; stopCount=0;
r.stops.forEach(s=>addStop(s.value,s.coord));
document.getElementById('corridorWidth').value=r.corridor||'10000';
toast('Rota yuklendi: '+r.name);
}
function deleteSavedRoute(){
const sel=document.getElementById('savedRoutesSel');
const idx=parseInt(sel.value);
if(isNaN(idx)){toast('Silinecek rotayi secin.');return}
const routes=getSavedRoutes();
routes.splice(idx,1);
routes.forEach((r,i)=>r.name=`${i+1}. Kaydedilen Rota`);
setSavedRoutes(routes);
loadSavedRoutesUI();
toast('Rota silindi.');
}
function getLatLng(mosque){
const loc=mosque.geometry&&mosque.geometry.location;
if(!loc) return {lat:0,lng:0};
return {
lat: loc._lat !== undefined ? loc._lat : (typeof loc.lat==='function' ? loc.lat() : loc.lat),
lng: loc._lng !== undefined ? loc._lng : (typeof loc.lng==='function' ? loc.lng() : loc.lng),
};
}
let _userPinMarker = null;
let _userPinCircle = null;
function placeUserPin(loc){
if(_userPinMarker){ _userPinMarker.map=null; _userPinMarker=null; }
if(_userPinCircle){ _userPinCircle.setMap(null); _userPinCircle=null; }
const el=document.createElement('div');
el.style.cssText=`width:14px;height:14px;border-radius:50%;background:#2d6a4f;border:3px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,.4)`;
_userPinMarker=new AdvancedMarkerElement({position:loc,map,content:el,title:'Konumunuz'});
_userPinCircle=new google.maps.Circle({map,center:loc,radius:120,fillColor:'#52b788',fillOpacity:.15,strokeColor:'#52b788',strokeOpacity:.4,strokeWeight:1});
}
function makeMosqueMarker(mosque, index, type){
const {lat,lng}=getLatLng(mosque);
if(!lat&&!lng)return null;
const m=makeAdvMarker({lat,lng},'#1565c0',1.0,mosque.name);
m.addListener('gmp-click',()=>openInfo(mosque,m,index,type));
return m;
}
function openInfo(mosque, marker, index, type){
const {lat,lng}=getLatLng(mosque);
const pid=mosque.place_id;
const mapsUrl =`https://www.google.com/maps/place/?q=place_id:${pid}`;
const routeUrl=`https://www.google.com/maps/dir/?api=1&destination=${lat},${lng}&destination_place_id=${pid}&travelmode=driving`;
infoWindow.setContent(`
<div class="iw">
<div class="iw-name">${index+1}. ${mosque.name}</div>
<div class="iw-addr">${mosque.vicinity||''}</div>
<div class="iw-stats">
<span>&#9733; <strong>${mosque.rating?mosque.rating.toFixed(1):'—'}</strong></span>
<span>&#128172; <strong>${fmt(mosque.user_ratings_total)}</strong> yorum</span>
</div>
<div class="iw-btns">
<a class="iw-btn iw-maps" href="${mapsUrl}" target="_blank" rel="noopener">Maps'te Gor</a>
<a class="iw-btn iw-rota" href="${routeUrl}" target="_blank" rel="noopener">Rota Olustur</a>
</div>
</div>`);
infoWindow.open({map,anchor:marker});
highlightCard(index,type);
}
function renderList(listId, mosques, type){
document.getElementById(listId).innerHTML=mosques.map((m,i)=>`
<div class="mcard ${i===0?'active':''} ${type==='route'?'on-route':''}"
id="${type}-card-${i}" onclick="selectMosque(${i},'${type}')">
<div class="ctop">
<div class="mname">${m.name}</div>
<div class="rnk ${type==='route'?'rnk-r':'rnk-n'}">#${i+1}</div>
</div>
<div class="maddr">${m.vicinity||''}</div>
<div class="mstats">
<div class="stat"><span>&#128172;</span><span class="sv">${fmt(m.user_ratings_total)}</span><span class="sl"> yorum</span></div>
<div class="stat"><span>&#9733;</span><span class="sv">${m.rating?m.rating.toFixed(1):'—'}</span></div>
<div class="stars">${starsHtml(m.rating)}</div>
</div>
</div>`).join('');
}
function selectMosque(index, type){
const list=type==='nearby'?nearbyMosques:routeMosques;
const pins=type==='nearby'?nearbyMarkers:routeMarkers;
const m=list[index];if(!m)return;
const {lat,lng}=getLatLng(m);
map.panTo({lat,lng}); map.setZoom(16);
openInfo(m,pins[index],index,type);
}
function highlightCard(index, type){
const prefix=type+'-card-';
document.querySelectorAll(`[id^="${prefix}"]`).forEach((c,i)=>c.classList.toggle('active',i===index));
document.getElementById(prefix+index)?.scrollIntoView({behavior:'smooth',block:'nearest'});
}
function showLoading(id){document.getElementById(id).innerHTML=`<div class="smsg">${spin(30)}<h3>Araniyor...</h3><p>Kaliteli camiler filtreleniyor...</p></div>`}
function showEmpty(id,msg){document.getElementById(id).innerHTML=`<div class="smsg"><div class="ico">&#128269;</div><h3>Sonuc Bulunamadi</h3><p>${msg}</p></div>`}
document.getElementById('originInput').addEventListener('keydown',e=>{if(e.key==='Enter')startRoute()});
document.getElementById('destInput').addEventListener('keydown', e=>{if(e.key==='Enter')startRoute()});
document.addEventListener('keydown',e=>{if(e.key==='Escape')cancelPicking()});
document.getElementById('originInput').addEventListener('input',function(){this.dataset.coord='';this.dataset.useGPS='';});
document.getElementById('destInput').addEventListener('input',function(){this.dataset.coord='';});